import{o as i,c as n,j as t,n as s,e as o,ae as l,p}from"./chunks/framework.BSk3HXt1.js";const d={class:"language-toggle-wrapper"},c={class:"language-toggle-bar"},h={class:"bilingual-title"},u={key:0,class:"zh-text"},g={key:1,class:"en-text"},x=JSON.parse('{"title":"川普率科技巨頭訪北京：華麗排場背後的暗流與台灣紅線 | Trump Brought Top CEOs to Beijing but Few Big Deals Emerge","description":"","frontmatter":{"outline":[2,3],"title":"川普率科技巨頭訪北京：華麗排場背後的暗流與台灣紅線 | Trump Brought Top CEOs to Beijing but Few Big Deals Emerge"},"headers":[],"relativePath":"news/trump-beijing-summit-ceos.md","filePath":"news/trump-beijing-summit-ceos.md"}'),m={name:"news/trump-beijing-summit-ceos.md"},w=Object.assign(m,{setup(v){const e=p("bilingual");return(b,a)=>(i(),n("div",null,[t("div",d,[t("div",c,[t("button",{class:s(["language-toggle-btn",{active:e.value==="bilingual"}]),onClick:a[0]||(a[0]=r=>e.value="bilingual")}," 中英雙語 (Bilingual) ",2),t("button",{class:s(["language-toggle-btn",{active:e.value==="zh"}]),onClick:a[1]||(a[1]=r=>e.value="zh")}," 純中文 (Chinese) ",2),t("button",{class:s(["language-toggle-btn",{active:e.value==="en"}]),onClick:a[2]||(a[2]=r=>e.value="en")}," 純英文 (English) ",2)])]),t("div",{class:s("bilingual-article mode-"+e.value)},[t("h1",h,[e.value!=="en"?(i(),n("span",u,"川普率科技巨頭訪北京：華麗排場背後的暗流與台灣紅線")):o("",!0),e.value!=="zh"?(i(),n("span",g,"Trump Brought Top CEOs to Beijing but Few Big Deals Emerge")):o("",!0)]),a[3]||(a[3]=l('<div style="text-align:center;margin:24px 0 32px 0;"><img src="/ai-news/trump-beijing-summit-ceos/hero.png" alt="Trump Beijing Summit" style="border-radius:16px;max-width:100%;box-shadow:0 8px 32px rgba(0,0,0,0.15);border:1px solid rgba(255,255,255,0.08);"></div><div class="bilingual-paragraph"><p class="zh-text">隨著美國總統唐納·川普與中國國家主席習近平在北京舉行最後一輪會談，這場備受矚目的峰會迄今為止釋出了溫馨的言辭與精心策劃的象徵意義——但鮮少有實質性的重大經濟成果。</p><p class="en-text">As US President Donald Trump and his Chinese counterpart Xi Jinping hold their final round of talks in Beijing, the summit has so far produced warm words and carefully managed symbolism - but few big economic outcomes.</p></div><div class="bilingual-paragraph"><p class="zh-text">峰會的第一天展現了盛大的典禮、顯赫的商業領袖，以及對美中關係未來的樂觀表述；然而，兩國既沒有達成全方位的貿易突破，官方宣布的重大商業協議也寥寥無幾。</p><p class="en-text">Day one featured grand ceremonies, prominent business leaders and optimistic language about the future of US-China ties, but there has been no sweeping trade breakthrough and little in the way of major business agreements announced.</p></div><div class="bilingual-paragraph"><p class="zh-text">美國總統川普週四與習近平進行了兩個多小時的會談，並形容美中關係為「世界上最舉足輕重的經濟關係」。</p><p class="en-text">US President Donald Trump met Chinese President Xi Jinping on Thursday for more than two hours of talks, describing the US-China relationship as &quot;the world&#39;s most consequential economic relationship&quot;.</p></div><div class="bilingual-paragraph"><p class="zh-text">白宮將此次會晤定調為「富有成效」。而在人民大會堂發表講話的川普，更是直言這「可能是史上規模最大的峰會」。</p><p class="en-text">The White House called the meeting &quot;highly productive&quot;. For Trump, speaking at the Great Hall of the People, it was potentially &quot;the biggest summit ever&quot;.</p></div><div class="bilingual-paragraph"><p class="zh-text">習近平表示，先前兩國在韓國舉行的貿易談判取得了「進展」，但他隨後發出針對台灣問題的嚴正警告：「如果處理不當，兩國可能會發生碰撞，甚至爆發衝突。」</p><p class="en-text">Previous trade negotiations between the two countries in South Korea had delivered &quot;progress&quot;, Xi said, but he paired that with a stark warning on Taiwan, saying: &quot;If mishandled, the two nations could collide or even come into conflict.&quot;</p></div><hr><h2 id="🤖-科技與貿易爭霸-tech-and-trade" tabindex="-1">🤖 科技與貿易爭霸 (Tech and Trade) <a class="header-anchor" href="#🤖-科技與貿易爭霸-tech-and-trade" aria-label="Permalink to &quot;🤖 科技與貿易爭霸 (Tech and Trade)&quot;">​</a></h2><div class="bilingual-paragraph"><p class="zh-text">這是一次「門面功夫」與「實質成果」同等重要的出訪。其中最受外界放大檢視的瞬間，就發生在空軍一號降落北京之時。</p><p class="en-text">This was a visit where optics have mattered as much as outcomes, with one of the most closely watched moments coming as Air Force One touched down in Beijing.</p></div><div class="bilingual-paragraph"><p class="zh-text">伊隆·馬斯克（Elon Musk）搶在皮特·海格塞斯、馬可·魯比歐等內閣高官，以及美國貿易代表詹姆森·格里爾之前，率先走下總統專機——這場出訪注定會被「貿易」二字所定義。</p><p class="en-text">Elon Musk stepped off the presidential aircraft ahead of senior cabinet officials including Pete Hegseth, Marco Rubio and US Trade Representative Jamieson Greer - on a trip that was always going to be defined by trade.</p></div><div class="bilingual-paragraph"><p class="zh-text">馬斯克與輝達（Nvidia）執行長黃仁勳在歡迎儀式中始終緊跟在川普身旁。</p><p class="en-text">Musk and Nvidia chief Jensen Huang also remained close to Trump during the welcome ceremony.</p></div><div class="bilingual-paragraph"><p class="zh-text">這種強烈的象徵意義令人難以忽視。馬斯克與黃仁勳恰恰代表了美中經濟關係中最敏感的兩大壓力點：電動車與人工智慧（AI）半導體晶片。</p><p class="en-text">The symbolism was hard to miss. Musk and Huang represent some of the most sensitive pressure points in the US-China economic relationship: electric vehicles, artificial intelligence (AI) and semiconductor microchips.</p></div><div class="bilingual-paragraph"><p class="zh-text">兩家企業的命脈也都與中國市場深陷交織。特斯拉極度仰賴其上海超級工廠與中國消費者；而輝達的晶片則正處於全球人工智慧軍備競賽的核心，同時也是美國限制中國獲取先進計算能力之出口管制的頭號對象。</p><p class="en-text">Both are also exposed to China. Tesla depends heavily on its Shanghai gigafactory and Chinese consumers, while Nvidia&#39;s chips sit at the centre of the global AI race and US export controls designed to limit China&#39;s access to advanced computing.</p></div><div class="bilingual-paragraph"><p class="zh-text">黃仁勳的現身尤其引人矚目，因為他最初並不在官方的代表團名單上，這引發了外界的廣泛猜測：在這次閉門對談中，人工智慧與晶片取得權的議題，其核心重要性可能遠超原先的預期。</p><p class="en-text">Huang&#39;s presence was particularly notable given he was not on the original delegation list, fuelling speculation that AI and chip access may feature more centrally in discussions than previously expected.</p></div><div class="bilingual-paragraph"><p class="zh-text">川普隨後在接受福斯新聞（Fox News）採訪時提到：「中國將與這些人投資數千億美元，」但並未透露更具體的細節。</p><p class="en-text">Trump later told Fox News that &quot;China is going to invest hundreds of billions of dollars with those people,&quot; without giving further details.</p></div><div class="bilingual-paragraph"><p class="zh-text">波音公司執行長凱利·奧特伯格（Kelly Ortberg）也是此次美國代表團的一員。</p><p class="en-text">Boeing chief executive Kelly Ortberg is also part of the the US delegation.</p></div><div class="bilingual-paragraph"><p class="zh-text">在同一次採訪中，川普表示中國已同意訂購 200 架波音客機，這是近十年來中國首次採購美國製造的商用噴射機。</p><p class="en-text">In the same interview, Trump said China had agreed to order 200 Boeing jets, its first purchase of US-made commercial jets in nearly a decade.</p></div><div class="bilingual-paragraph"><p class="zh-text">然而，這項採購數字低於市場分析師的原先預期。川普言論發表後，波音公司股價跌幅超過 4%。</p><p class="en-text">But that is less than many analysts had expected. Boeing shares fell more than 4% after the comments were aired.</p></div><hr><h2 id="🤝-無實質協議-脆弱的貿易休戰延續-fragile-trade-truce-continues" tabindex="-1">🤝 無實質協議，脆弱的貿易休戰延續 (Fragile Trade Truce Continues) <a class="header-anchor" href="#🤝-無實質協議-脆弱的貿易休戰延續-fragile-trade-truce-continues" aria-label="Permalink to &quot;🤝 無實質協議，脆弱的貿易休戰延續 (Fragile Trade Truce Continues)&quot;">​</a></h2><div class="bilingual-paragraph"><p class="zh-text">儘管排場華麗，雙方卻未達成任何重大的貿易協議或結構性協議。</p><p class="en-text">Despite the choreography, there was no major trade deal or structural agreement.</p></div><div class="bilingual-paragraph"><p class="zh-text">相反地，雙方都強調將延續去年十月的貿易停火協定。根據該協議，華盛頓暫停了對中國商品大幅加徵關稅，而北京則放寬了對稀土出口的限制。</p><p class="en-text">Both sides instead pointed to continuity in the October trade truce, under which Washington suspended steep tariff increases on Chinese goods while Beijing eased back from restricting rare earth exports.</p></div><div class="bilingual-paragraph"><p class="zh-text">白宮表示，兩國領導人同意成立一個「貿易委員會」（Board of Trade），以便在無需重啟關稅談判的前提下，隨時管理和調節兩國的經貿關係。</p><p class="en-text">The White House said both leaders agreed to establish a &quot;Board of Trade&quot; - to manage the relationship without having to reopen tariff negotiations.</p></div><div class="bilingual-paragraph"><p class="zh-text">一直代表華府主導貿易談判的美國財政部長史考特·貝森特（Scott Bessent）在接受 CNBC 預錄採訪時表示，他預期在建立支持未來雙邊投資的機制上也會有所進展。</p><p class="en-text">US Treasury Secretary Scott Bessent, who has been leading trade talks for Washington, said in a pre-recorded interview with business news channel CNBC that he expected progress on a mechanism to support future investment too.</p></div><div class="bilingual-paragraph"><p class="zh-text">然而，美國官員警告稱，在這些機制完全投入運作之前，仍有大量的談判工作需要完成。</p><p class="en-text">US officials have cautioned, however, that there is a lot of work to be done before these can be fully operational.</p></div><hr><h2 id="🌾-市場准入與雙邊合作-market-access-and-co-operation" tabindex="-1">🌾 市場准入與雙邊合作 (Market Access and Co-operation) <a class="header-anchor" href="#🌾-市場准入與雙邊合作-market-access-and-co-operation" aria-label="Permalink to &quot;🌾 市場准入與雙邊合作 (Market Access and Co-operation)&quot;">​</a></h2><div class="bilingual-paragraph"><p class="zh-text">根據白宮的聲明，會談內容包括討論擴大美國企業在中國的市場准入，以及增加中國對美國工業的投資。</p><p class="en-text">According to the White House, the talks included discussion of expanding Chinese market access for US companies and increasing Chinese investment into US industries.</p></div><div class="bilingual-paragraph"><p class="zh-text">北京確實釋出了將增加採購美國農產品和能源產品的信號。</p><p class="en-text">Beijing did signal it would increase purchases of US agricultural and energy products.</p></div><div class="bilingual-paragraph"><p class="zh-text">美國農民一直期盼中國能進一步開放大豆、牛肉、家禽的進口市場，但目前尚未宣布具體細節。</p><p class="en-text">Farmers in the US have been seeking more Chinese access for soybeans, beef, poultry, but no firm details were announced.</p></div><div class="bilingual-paragraph"><p class="zh-text">財政部長貝森特淡化了外界對農產品出現重大突破的預期，暗示部分大豆採購承諾在先前的協議中已獲得解決，但他提到中國擴大採購美國能源——特別是液化天然氣（LNG）——仍有相當大的潛在空間。</p><p class="en-text">Bessent played down expectations of major new breakthroughs on agricultural goods, suggesting that some soybean commitments had already been addressed under previous agreements, but said there was scope for China to increase purchases of US energy, including liquefied natural gas (LNG).</p></div><div class="bilingual-paragraph"><p class="zh-text">據新華社報導，習近平告訴美國商業領袖，中國的「大門會越開越大」，美國企業在中國市場將擁有「更廣闊的前景」。</p><p class="en-text">Xi told US business leaders that China&#39;s &quot;doors will open wider&quot; and that American firms would have &quot;broader prospects&quot; in the Chinese market, according to news site Xinhua.</p></div><div class="bilingual-paragraph"><p class="zh-text">他也呼籲擴大兩國在貿易、農業、醫療衛生、旅遊和執法領域的合作，稱雙邊關係為「互利共贏」。</p><p class="en-text">He also called for expanded cooperation in trade, agriculture, healthcare, tourism and law enforcement, describing bilateral ties as &quot;mutually beneficial&quot; and delivering &quot;win-win results&quot;.</p></div><div class="bilingual-paragraph"><p class="zh-text">但對於多數美商而言，中國雖是龐大市場，卻也因為繁雜的法規、官僚作風與地緣政治的不確定性，仍舊是一個極具挑戰的營商環境。</p><p class="en-text">For US companies, China remains both a major market and a difficult operating environment due to regulation, red tape and geopolitical uncertainty.</p></div><hr><h2 id="⚠️-最敏感的核心紅線-台灣問題-the-most-sensitive-issue" tabindex="-1">⚠️ 最敏感的核心紅線：台灣問題 (The &#39;Most Sensitive&#39; Issue) <a class="header-anchor" href="#⚠️-最敏感的核心紅線-台灣問題-the-most-sensitive-issue" aria-label="Permalink to &quot;⚠️ 最敏感的核心紅線：台灣問題 (The &#39;Most Sensitive&#39; Issue)&quot;">​</a></h2><div class="bilingual-paragraph"><p class="zh-text">這場峰會釋出最顯著的風向轉變，在於北京當局如今更為直接地將「台灣問題」與美中整體的經濟與貿易關係牢牢綁定。</p><p class="en-text">One of the clearest shifts emerging from the summit was how directly Beijing is now linking Taiwan to the broader economic relationship with the United States.</p></div><div class="bilingual-paragraph"><p class="zh-text">在過去一年的貿易談判中，台灣大多僅被視為美中之間數個摩擦點之一——主要涉及美國與台灣半導體公司的合作、美台貿易關係以及對台軍售。</p><p class="en-text">Over the past year of trade talks, Taiwan had largely been treated as one of several friction points between the US and China - particularly US collaboration with semiconductor companies, US-Taiwan trade ties, and arms sales to Taipei.</p></div><div class="bilingual-paragraph"><p class="zh-text">然而，中方在此次會晤中傳遞的訊息表明，台灣問題越來越被塑造成為「美中貿易關係能否維繫的先決條件」。</p><p class="en-text">But Chinese messaging from the meeting suggested Taiwan is increasingly being framed as a condition for the US-China trade relationship.</p></div><div class="bilingual-paragraph"><p class="zh-text">根據北京發布的新聞通稿，習近平表示雙方已同意基於「建設性的戰略穩定」為雙邊關係建立「新定位」，但他同時警告：台灣問題仍是其中最敏感的核心。</p><p class="en-text">According to Beijing&#39;s readout, Xi said the two sides had agreed to a &quot;new positioning&quot; for relations based on &quot;constructive strategic stability&quot;, but warned that Taiwan remained the most sensitive issue.</p></div><div class="bilingual-paragraph"><p class="zh-text">據中國官方媒體報導，習近平在會談中嚴正指出：「台灣問題是中美關係中最核心、最敏感的問題。」</p><p class="en-text">&quot;The Taiwan question is the most important issue in China-US relations,&quot; Xi warned during the talks, according to Chinese state media.</p></div><div class="bilingual-paragraph"><p class="zh-text">他再度強調：「如果處理不當，兩國可能會產生碰撞，甚至爆發衝突。」</p><p class="en-text">&quot;If mishandled, the two nations could collide or even come into conflict,&quot; he said.</p></div><hr><h2 id="⚡-懸而未決的科技鴻溝與能源變數-unresolved-fault-lines" tabindex="-1">⚡ 懸而未決的科技鴻溝與能源變數 (Unresolved Fault Lines) <a class="header-anchor" href="#⚡-懸而未決的科技鴻溝與能源變數-unresolved-fault-lines" aria-label="Permalink to &quot;⚡ 懸而未決的科技鴻溝與能源變數 (Unresolved Fault Lines)&quot;">​</a></h2><div class="bilingual-paragraph"><p class="zh-text">毫無疑問，「科技」仍舊是橫亙在美中兩國之間最難以跨越的深淵。</p><p class="en-text">Technology remains the biggest divide between the US and China.</p></div><div class="bilingual-paragraph"><p class="zh-text">美國旨在限制中國染指前沿 AI 技術研發的「先進半導體與晶片製造設備出口禁令」，如今依然沒有絲毫鬆動跡象。</p><p class="en-text">US export controls on advanced semiconductors and chipmaking equipment - aimed at limiting China&#39;s access to frontier AI capabilities - remain in place.</p></div><div class="bilingual-paragraph"><p class="zh-text">北京方面則持續爭取獲取先進技術的管道，同時不斷抨擊美方是在處心積慮地扼殺中國的工業發展。</p><p class="en-text">Beijing continues to push for greater access to advanced technologies, while criticising what it sees as efforts to constrain its industrial development.</p></div><div class="bilingual-paragraph"><p class="zh-text">雖然外界原本預期人工智慧（AI）會是本次商議的重頭戲，但在首日的各類官方報告中均隻字未提。</p><p class="en-text">Artificial intelligence (AI) was expected to be a big part of conversations but there was no mention of it in readouts from the first day of the summit.</p></div><div class="bilingual-paragraph"><p class="zh-text">財長貝森特透露，代表團正在峰會上討論 AI 的安全防線（guardrails），並補充說「極其重要」的是：美國必須在人工智慧領域持續保持領先中國的地位。</p><p class="en-text">Bessent said that delegations are discussing AI guardrails at the ​summit, adding that it was &quot;of utmost importance&quot; that the US maintain its lead over China in AI.</p></div><div class="bilingual-paragraph"><p class="zh-text">「我們不希望做的是扼殺創新。我們的職責是提出最精密的演算邏輯，在極大化創新的同時，確保最高規格的安全保護。」貝森特表示。</p><p class="en-text">&quot;What we don&#39;t want to do is stifle innovation. So our responsibility is ​to come up with the highest performance calculus where we can get ⁠the most innovation and the highest level of safety,&quot; Bessent said.</p></div><div class="bilingual-paragraph"><p class="zh-text">此外，川普在會中亦試圖在伊朗衝突與石油市場穩定性上尋求中方的配合。油價的大幅波動與供應線路受阻，近期顯著推高了中國的進口成本，也推升了全球物價。</p><p class="en-text">Trump also entered the talks hoping for Chinese cooperation on the Iran conflict and oil market stability. Oil price volatility and repeated disruptions to supply routes have increased China&#39;s import costs and pushed up prices across the world.</p></div><div class="bilingual-paragraph"><p class="zh-text">川普表示，中國可以動用其影響力去施壓伊朗，以穩定荷姆茲海峽（全球能源大動脈）的航行自由與安全。中方發出的訊息亦顯示有討論到中東議題，但細節依舊點到為止。</p><p class="en-text">Trump has said that China could use its influence to encourage Iran to stabilise flows through the Strait of Hormuz, a key global energy artery. Chinese readouts indicated the Middle East was discussed, though again, details were limited.</p></div><div class="bilingual-paragraph"><p class="zh-text">在週四晚間於北京為川普舉辦的國宴上，美國總統川普已正式邀請習近平於 9 月 24 日訪問白宮。</p><p class="en-text">At the state banquet held for Trump in Beijing on Thursday evening, the US president invited Xi to ​the White House ​on ‌24 September.</p></div><div class="bilingual-paragraph"><p class="zh-text">在 9 月秋季峰會到來前，雙方預計將展開更多層級的角力與談判。各界也期盼這兩個全球最大的經濟體，在下一次會晤中能交出這次遺憾擦身而過的突破性貿易成果。</p><p class="en-text">Further discussions between the two sides are expected ahead of that summit, with the hope that the world&#39;s two biggest economies can deliver a major breakthough on trade that proved elusive this time around.</p></div><div class="original-source-wrapper"><div class="source-label"><span class="zh-text">🌐 閱讀英文原文：</span><span class="en-text">🌐 Read Original Article:</span></div><a href="https://www.bbc.com/news/articles/clypj01189lo" target="_blank" rel="noopener noreferrer" class="source-link-btn"> BBC News <span style="font-size:0.8rem;">↗</span></a></div>',55))],2)]))}});export{x as __pageData,w as default};
